With.Query:

				SELECT {{
							Fields
								-Dimension: PointsOfSale 
									--Table: PointsOfSaleCte
								-Dimension: Products 
									--Table: ProductsCte
								-Dimension: Calendar 
									--Table: CalendarCte
									--WithRequestedFields
								-WithComma
                		}}
                		Sales3.SalesQuantity, Sales3.AmountTaxesExcluded, Sales3.SalesTurnover, Sales3.Refund
                	FROM Fact.Sales3
                	{{
                		InnerJoin 
                			-Dimension: PointsOfSale 
                				--Table: PointsOfSaleCte
							-Table:Sales3
							-On:PointOfSaleId-PointOfSaleId
                	}}
                	{{
                		InnerJoin 
                			-Dimension: Products 
                				--Table: ProductsCte
							-Table: Sales3
							-On: ProductId-ProductId
                	}}
                	{{
                		InnerJoin 
                			-Dimension: Calendar 
                				--Required
                				--Table: CalendarCte
							-Table: Sales3
							-On:Date-Date
                	}}
					{{
                		OrderBy
                			-Dimension: PointsOfSale
								--Table: PointsOfSaleCte
	            			-Dimension: Products
								--Table: ProductsCte
							-Dimension: Calendar
								--Table: CalendarCte
							-Required
	            	}}
					{{Pagination}}
